pub(crate) fn selector_lex_context(p: &mut CssParser) -> CssLexContext {
    // It's an inverted logic for `is_nth_at_selector(p, 1)`.
    if p.nth_at_ts(1, SELECTOR_LEX_SET) {
        CssLexContext::Regular
    } else {
        CssLexContext::Selector
    }
}

